const request = $input.first().json;
const rawHeaders = (request.headers && typeof request.headers === 'object' && !Array.isArray(request.headers)) ? request.headers : {};
const headers = Object.fromEntries(
  Object.entries(rawHeaders).map(([key, value]) => [String(key).toLowerCase(), value])
);
const sanitizedHeaders = Object.fromEntries(
  Object.entries(rawHeaders).filter(([key]) => {
    const normalizedKey = String(key).toLowerCase();
    return normalizedKey !== 'x-api-key' && normalizedKey !== 'authorization';
  })
);
const sanitizedRequest = {
  ...request,
  headers: sanitizedHeaders
};
const headerValue = (value) => Array.isArray(value) ? String(value[0] || '').trim() : String(value || '').trim();
const expectedApiKey = String($env.N8N_WEBHOOK_API_KEY || '').trim();
const xApiKey = headerValue(headers['x-api-key']);
const authorization = headerValue(headers.authorization);
const bearerMatch = authorization.match(/^Bearer\s+(.+)$/i);
const bearerToken = bearerMatch ? String(bearerMatch[1] || '').trim() : '';
const matchedXApiKey = Boolean(expectedApiKey) && xApiKey === expectedApiKey;
const matchedBearer = Boolean(expectedApiKey) && bearerToken === expectedApiKey;
const authenticated = matchedXApiKey || matchedBearer;

if (authenticated) {
  return [{
    json: {
      ...sanitizedRequest,
      webhook_auth: {
        authenticated: true,
        header: matchedXApiKey ? 'X-API-Key' : 'Authorization'
      }
    },
    pairedItem: {
      item: 0
    }
  }];
}

const message = 'Unauthorized: Invalid or missing API key';

return [{
  json: {
    ...sanitizedRequest,
    status: 'error',
    message,
    code: 401,
    webhook_auth: {
      authenticated: false
    }
  },
  pairedItem: {
    item: 0
  }
}];

const sha256Hex = (value) => {
  const rightRotate = (word, bits) => (word >>> bits) | (word << (32 - bits));
  const K = [
    0x428a2f98, 0x71374491, 0xb5c0fbcf, 0xe9b5dba5, 0x3956c25b, 0x59f111f1, 0x923f82a4, 0xab1c5ed5,
    0xd807aa98, 0x12835b01, 0x243185be, 0x550c7dc3, 0x72be5d74, 0x80deb1fe, 0x9bdc06a7, 0xc19bf174,
    0xe49b69c1, 0xefbe4786, 0x0fc19dc6, 0x240ca1cc, 0x2de92c6f, 0x4a7484aa, 0x5cb0a9dc, 0x76f988da,
    0x983e5152, 0xa831c66d, 0xb00327c8, 0xbf597fc7, 0xc6e00bf3, 0xd5a79147, 0x06ca6351, 0x14292967,
    0x27b70a85, 0x2e1b2138, 0x4d2c6dfc, 0x53380d13, 0x650a7354, 0x766a0abb, 0x81c2c92e, 0x92722c85,
    0xa2bfe8a1, 0xa81a664b, 0xc24b8b70, 0xc76c51a3, 0xd192e819, 0xd6990624, 0xf40e3585, 0x106aa070,
    0x19a4c116, 0x1e376c08, 0x2748774c, 0x34b0bcb5, 0x391c0cb3, 0x4ed8aa4a, 0x5b9cca4f, 0x682e6ff3,
    0x748f82ee, 0x78a5636f, 0x84c87814, 0x8cc70208, 0x90befffa, 0xa4506ceb, 0xbef9a3f7, 0xc67178f2,
  ];
  const hash = [
    0x6a09e667, 0xbb67ae85, 0x3c6ef372, 0xa54ff53a,
    0x510e527f, 0x9b05688c, 0x1f83d9ab, 0x5be0cd19,
  ];
  const encoded = unescape(encodeURIComponent(value));
  const bytes = Array.from(encoded, (char) => char.charCodeAt(0));
  const bitLength = bytes.length * 8;

  bytes.push(0x80);
  while ((bytes.length % 64) !== 56) {
    bytes.push(0);
  }

  const highBits = Math.floor(bitLength / 0x100000000);
  const lowBits = bitLength >>> 0;
  bytes.push(
    (highBits >>> 24) & 0xff,
    (highBits >>> 16) & 0xff,
    (highBits >>> 8) & 0xff,
    highBits & 0xff,
    (lowBits >>> 24) & 0xff,
    (lowBits >>> 16) & 0xff,
    (lowBits >>> 8) & 0xff,
    lowBits & 0xff,
  );

  const schedule = new Array(64);
  for (let offset = 0; offset < bytes.length; offset += 64) {
    for (let index = 0; index < 16; index += 1) {
      const byteOffset = offset + index * 4;
      schedule[index] = (
        (bytes[byteOffset] << 24)
        | (bytes[byteOffset + 1] << 16)
        | (bytes[byteOffset + 2] << 8)
        | bytes[byteOffset + 3]
      ) >>> 0;
    }

    for (let index = 16; index < 64; index += 1) {
      const s0 = rightRotate(schedule[index - 15], 7) ^ rightRotate(schedule[index - 15], 18) ^ (schedule[index - 15] >>> 3);
      const s1 = rightRotate(schedule[index - 2], 17) ^ rightRotate(schedule[index - 2], 19) ^ (schedule[index - 2] >>> 10);
      schedule[index] = (schedule[index - 16] + s0 + schedule[index - 7] + s1) >>> 0;
    }

    let [a, b, c, d, e, f, g, h] = hash;

    for (let index = 0; index < 64; index += 1) {
      const s1 = rightRotate(e, 6) ^ rightRotate(e, 11) ^ rightRotate(e, 25);
      const choice = (e & f) ^ (~e & g);
      const temp1 = (h + s1 + choice + K[index] + schedule[index]) >>> 0;
      const s0 = rightRotate(a, 2) ^ rightRotate(a, 13) ^ rightRotate(a, 22);
      const majority = (a & b) ^ (a & c) ^ (b & c);
      const temp2 = (s0 + majority) >>> 0;

      h = g;
      g = f;
      f = e;
      e = (d + temp1) >>> 0;
      d = c;
      c = b;
      b = a;
      a = (temp1 + temp2) >>> 0;
    }

    hash[0] = (hash[0] + a) >>> 0;
    hash[1] = (hash[1] + b) >>> 0;
    hash[2] = (hash[2] + c) >>> 0;
    hash[3] = (hash[3] + d) >>> 0;
    hash[4] = (hash[4] + e) >>> 0;
    hash[5] = (hash[5] + f) >>> 0;
    hash[6] = (hash[6] + g) >>> 0;
    hash[7] = (hash[7] + h) >>> 0;
  }

  return hash.map((part) => part.toString(16).padStart(8, '0')).join('');
};

// Validate input
const input = $input.first().json.body;
const normalizedText = String(input?.text || '').trim();

if (!input?.tenant_id || !input?.scope || !normalizedText) {
  return [{
    json: {
      error: 'Missing required fields: tenant_id, scope, text'
    }
  }];
}

// Secret patterns to reject
const secretPatterns = [
  /api[_-]?key/i,
  /bearer\s+[A-Za-z0-9-_.]+/i,
  /-----BEGIN(.*?)PRIVATE KEY-----/i
];

// Check for secrets in text
if (secretPatterns.some((p) => p.test(normalizedText))) {
  return [{
    json: {
      error: 'Rejected: potential secret detected in text'
    }
  }];
}

// Filter facts - only keep those with confidence >= 0.75 OR source == explicit
const filteredFacts = (input.facts || []).filter((f) => {
  // Check for secrets in fact fields
  const factText = `${f.subject || ''} ${f.predicate || ''} ${f.object || ''}`;
  if (secretPatterns.some((p) => p.test(factText))) {
    return false;
  }

  // Apply commit rules
  if (f.confidence >= 0.75 || input.source === 'explicit') {
    // Reject if subject/predicate/object empty
    if (!f.subject || !f.predicate || !f.object) {
      return false;
    }
    return true;
  }
  return false;
});

const requestId = input.request_id || `req-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
const source = String(input.source || 'unknown');
const tags = Array.isArray(input.tags) ? input.tags : [];
const metadata = (input.metadata && typeof input.metadata === 'object' && !Array.isArray(input.metadata))
  ? input.metadata
  : {};
const contentHash = sha256Hex(normalizedText);

return [{
  json: {
    tenant_id: input.tenant_id,
    scope: input.scope,
    text: normalizedText,
    facts: filteredFacts,
    source,
    tags,
    metadata,
    request_id: requestId,
    content_hash: contentHash
  }
}];

const data = $input.first().json;

if (data.error) {
  return [{
    json: {
      status: 'error',
      message: data.error
    }
  }];
}

return [{
  json: data
}];

